impl Solution { pub fn number_of_right_triangles(grid: Vec<Vec<i32>>) -> i64 { let (m, n) = (grid.len(), grid[0].len()); let (mut r, mut c) = (vec![0i64; m], vec![0i64; n]); for i in 0..m { for j in 0..n { if grid[i][j] == 1 { r[i] += 1; c[j] += 1; } } } let mut black_ans = 0; for i in 0..m { for j in 0..n { if grid[i][j] == 1 { black_ans += (r[i] - 1) * (c[j] - 1); } } } black_ans } }